If you created an index that uses dynamic mappings, you can query the
`airbnb_mat_view` collection using the [queryString](querystring-ref)
operator. If you created an index that uses static mappings, you can
query the `airbnb_mat_view` collection using the
[autocomplete](autocomplete-ref) operator.

The code example performs the following tasks:

- Imports `mongodb` packages and dependencies.

- Establishes a connection to your cluster.

- Iterates over the cursor to print the documents that match the
  query.

The following query searches for properties where the property type
is `Apartment` or `Condominium`, accommodates `2` people, and
was listed in `2019`.

```csharp
using MongoDB.Bson;
using MongoDB.Bson.Serialization.Attributes;
using MongoDB.Bson.Serialization.Conventions;
using MongoDB.Driver;
using MongoDB.Driver.Search;

public class DateNumberToStringQuery
{
    private const string MongoConnectionString = "<connection-string>";

    public static void Main(string[] args)
    {
        // allow automapping of the camelCase database fields to our MovieDocument
        var camelCaseConvention = new ConventionPack { new CamelCaseElementNameConvention() };
        ConventionRegistry.Register("CamelCase", camelCaseConvention, type => true);

        // connect to your Atlas cluster
        var mongoClient = new MongoClient(MongoConnectionString);
        var airbnbDatabase = mongoClient.GetDatabase("sample_airbnb");
        var matViewCollection = airbnbDatabase.GetCollection<matViewDocument>("airbnb_mat_view");

        // define and run pipeline
        var results = matViewCollection.Aggregate()
            .Search(Builders<matViewDocument>.Search.QueryString(
                airbnb => airbnb.propertyType, 
                "(Apartment OR Condominium) AND accommodatesNumber: 4 AND lastScrapedDate: 2019"
                ),
                indexName: "date-number-fields-tutorial")
            .Limit(5)
            .Project<matViewDocument>(Builders<matViewDocument>.Projection
                .Exclude(airbnb => airbnb.Id))
            .ToList();

        // print results
        foreach (var airbnb in results) 
        {
            Console.WriteLine(airbnb.ToJson());
        }
    }
}

